from collections import defaultdict

class Solution(object):
    def maxWeight(self, n, edges, k, t):
        # dp[node][edges_used] = set of possible path weights ending at node with exactly edges_used edges
        # But tracking all possible weights is expensive; instead track max weight < t for each (node, edges)
        # dp[node][j] = max weight of a path ending at node using exactly j edges, weight < t
        # Initialize: dp[node][0] = 0 for all nodes (path of 0 edges)

        INF = float('inf')
        # dp[v][j] = max path weight ending at v with j edges, < t
        dp = [[-1] * (k + 1) for _ in range(n)]
        for v in range(n):
            dp[v][0] = 0  # 0-edge path at any node has weight 0

        adj = defaultdict(list)
        for u, v, w in edges:
            adj[u].append((v, w))

        # Process in topological order (DAG)
        # Since it's a DAG, we can use DP by iterating j from 1 to k
        for j in range(1, k + 1):
            new_dp = [[-1] * (k + 1) for _ in range(n)]
            # Copy previous
            for v in range(n):
                for jj in range(j):
                    new_dp[v][jj] = dp[v][jj]
            for u in range(n):
                if dp[u][j-1] == -1:
                    continue
                for v, w in adj[u]:
                    new_weight = dp[u][j-1] + w
                    if new_weight < t:
                        if new_weight > new_dp[v][j]:
                            new_dp[v][j] = new_weight
            dp = new_dp

        ans = -1
        for v in range(n):
            if dp[v][k] > ans:
                ans = dp[v][k]
        return ans
